def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
        else:
            score = 0
            for j in range(1, 6):
                weight = (6 - j)
                partial_ratio = ratio ** j
                if partial_ratio < 0.1:
                    score += weight * (1 - partial_ratio)
                elif partial_ratio < 0.5:
                    score += weight * (0.5 - partial_ratio) ** 2
                else:
                    score += weight * np.log1p(partial_ratio)
            if capacity < item * 1.5:
                score *= 1.2
            priorities[i] = score
    return priorities
